#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=1e6+5;
ll d[MAXN],sum,a[MAXN],c[MAXN],l[MAXN],r[MAXN],n,m,x=-1;
bool flag=true;
int main(void){
	scanf("%lld%lld",&n,&m);
	for(int i=1;i<=n;++i)
	{
		scanf("%lld",a+i);
	}
	for(int i=1;i<=m;++i)
	{
		scanf("%lld%lld%lld",c+i,l+i,r+i);
		d[l[i]]+=c[i];
		d[r[i]+1]-=c[i];
	}
	int j=m;
	for(int i=1;i<=n;++i)
	{
		sum+=d[i];
		if(sum>a[i])
		{
			while(sum>a[i])
			{
				d[l[j]]-=c[j],d[r[j]+1]+=c[j];
				if(l[j]<=i&&i<=r[j])sum-=c[j];j--;
			}
			if(flag)
			{
				x=j;flag=false;
			}
			else x=min(x,(ll)j);
		}
	}
	if(x==-1)printf("0");
	else printf("-1\n%lld",x+1);
	return false;
}
